mapper.select:
SELECT tmp.time, count(*) AS count FROM ( SELECT ( cur_price - pre_close_price )/ pre_close_price AS ud, DATE_FORMAT( cur_time, '%Y%m%d%H%i' ) AS time FROM stock_rt_info WHERE cur_time BETWEEN #{startDate} AND #{endDate} HAVING ud >= 0.1
<= -0.1
) AS tmp GROUP BY tmp.time;

SELECT
    MAX( sri.cur_time ) AS mxTime
FROM
    stock_rt_info AS sri
WHERE
    stock_code = #{stockCode}
  AND sri.cur_time BETWEEN #{startDate}
    AND #{endDate}

SELECT sri.trade_amount AS tradeAmt, sri.pre_close_price AS preClosePrice, sri.min_price AS lowPrice, sri.max_price AS highPrice, sri.open_price AS openPrice, sri.trade_volume AS tradeVol, sri.cur_price AS tradePrice, sri.cur_time AS curDate FROM stock_rt_info AS sri WHERE sri.stock_code = #{stockCode} AND cur_time IN ( SELECT MAX( cur_time ) AS mxTime FROM stock_rt_info WHERE stock_code = #{stockCode}
AND cur_time BETWEEN #{openDate}
AND #{endDate}
GROUP BY DATE_FORMAT( cur_time, '%y%m%d' ) );
